from abc import ABC, abstractmethod
import datetime

class HorodatageMixin:
    def get_temps(self):
        return datetime.datetime.now().isoformat()

class Loggable(ABC):
    @abstractmethod
    def log(self, msg: str): pass

class MonService(HorodatageMixin, Loggable):
    def log(self, msg: str):
        print(f"[{self.get_temps()}] {msg}")

